#............................Create a Caller Log (export to excel + techlog text file)
function create_techlog {
    # Define the path to the text file
    $filePath = "$FileDir\techlog_tmp.txt"
    $OutPutFile = "$savDir\tech-$cxb_name-$cxid_num-$timeS.txt"
    # Define the array of text to replace and their replacements
    $replacements = @{
    "~datetime~" = $timeS
    "ccr_num" = $ccr_num
    "cxn" = $cxn
    "cx_ph" = $cx_ph
    "cx_email" = $cx_email
    "cxb_name" = $cxb_name
    "cxid_num" = $cxid_num 
    "site_add" = $site_add
    "sum_x" = $sum_x
    }
    # Read the content of the file
    $fileContent = Get-Content -Path $filePath
    
    # Perform the replacements
    foreach ($key in $replacements.Keys) {
        $fileContent = $fileContent -replace $key, $replacements[$key]
    }
    
    # Write the updated content back to the file
    Set-Content -Path $OutPutFile  -Value $fileContent
}
#................................................................
#..........................append xlsx call log
function create_clog {
    $Excel = New-Object -ComObject Excel.Application
    # Perform operations...
    $Excel.Quit()
    [System.Runtime.Interopservices.Marshal]::ReleaseComObject($Excel)
    Stop-Process -Name "excel" -Force   
    $Excel = New-Object -ComObject Excel.Application
    $Excel.Visible = $false
    #Set Display alerts as false
    $Excel.displayalerts = $false
    $Workbook = $Excel.Workbooks.Open("$env:userprofile\OneDrive - AlticeUSA\Documents\ENOC-Ticket log\$Year\clog.xlsx")
    unblock-file -path "$env:userprofile\OneDrive - AlticeUSA\Documents\ENOC-Ticket log\$Year\clog.xlsx"
    $Worksheet = $Workbook.Worksheets.Item("clog$year")
    $Worksheet.Unprotect("clog$year")
    $xlUp = -4162
    # Find the last used cell in column B
    $lastRow = $worksheet.Cells.Item(1048576, 2).End($xlUp).Row
    # Next row to insert data
    $nextRow = $lastRow + 1
    $Worksheet.Cells.Item($nextRow, 2).Value = "$ccr_num"
    $Worksheet.Cells.Item($nextRow, 3) = Get-Date -DisplayHint Time
    $Worksheet.Cells.Item($nextRow, 4).Value = $cxn   
    $Worksheet.Cells.Item($nextRow, 5).Value = "$cx_email"   
    $Worksheet.Cells.Item($nextRow, 6).Value = "$cx_ph"
    $Worksheet.Cells.Item($nextRow, 7).Value = "$cxb_name"  
    $Worksheet.Cells.Item($nextRow, 8).Value = "$cxid_num"   
    $Worksheet.Cells.Item($nextRow, 9).Value = "$site_add"  
    $Worksheet.Cells.Item($nextRow, 10).Value = "$selcp"  
    $Worksheet.Cells.Item($nextRow, 13).Value = "$sum_x" 
    #Saving a workbooks to the hard drive
    $Workbook.Save()
    $Workbook.Close()
    $Excel.Quit()
    # Release COM objects to prevent memory leaks
    [System.Runtime.InteropServices.Marshal]::ReleaseComObject($worksheet) | Out-Null
    [System.Runtime.InteropServices.Marshal]::ReleaseComObject($workbook) | Out-Null
    [System.Runtime.InteropServices.Marshal]::ReleaseComObject($Excel) | Out-Null
    [System.GC]::Collect()
    [System.GC]::WaitForPendingFinalizers()   
    }
#..........................pull and update email template functions
function dipatch_req {
    # Create Word application object
    $Word = New-Object -ComObject Word.Application
    $Word.Visible = $false  # Set to $true for debugging
    Copy-Item -Path "$FileDir\dispatch_req.docx" -Destination "$env:userprofile\OneDrive - AlticeUSA\Documents\ENOC-Ticket log\$Year\$Month\$Day\email draft-$cxb_name-dispatch_req.docx"   
    # Open document (use full path)
    $Document = $Word.Documents.Open("$env:userprofile\OneDrive - AlticeUSA\Documents\ENOC-Ticket log\$Year\$Month\$Day\email draft-$cxb_name-dispatch_req.docx")

# Define replacements (use a hashtable for key-value pairs)
    $Replacements = @{
        "cxb_net_type" = $cxb_net_type
        "cxb_name" = $cxb_name
        "selcp" = $selcp
        "site_add" = $site_add
        "cxid_num" = $cxid_num
        "ccr_num" = $ccr_num
        "remedi_t" = $remedi_t
        "e_tk_num" = $e_tk_num
        }
    # Perform replacements
    foreach ($item in $Replacements.GetEnumerator()) {
        $FindText = $item.Key
        $ReplaceText = $item.Value
        $Document.Content.Find.Execute(
            $FindText,          # Find
            $false,             # MatchCase
            $true,              # MatchWholeWord
            $false,             # MatchWildcards
            $false,             # MatchSoundsLike
            $false,             # MatchAllWordForms
            $true,              # Forward
            1,                  # Wrap (wdFindContinue)
            $false,             # Format
            $ReplaceText,       # ReplaceWith
            2                   # Replace (wdReplaceAll)
        ) | Out-Null
    }

    # Save and close
    $Document.Save()
    $Document.Close()   
    }
