#...........................................Payload file integrity check.........................................
function file_int_chk {  
            #-------------------------------------
            $Destination = "$FileDir\logo.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            #-------------------------------------
            $Destination = "$FileDir\call.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            #-------------------------------------
            $Destination = "$FileDir\email.png"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_icons
                }
            #-------------------------------------
            #-------------------------------------
            $Destination = "$FileDir\techlog_tmp.txt"    
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_techlog
                }
            #-------------------------------------
            $Destination = "$env:userprofile\OneDrive - AlticeUSA\Documents\ENOC-Ticket log\$Year\clog.xlsx"
            if (!(Test-Path -Path $Destination)) {
                payload_deploy_clog
                }
            #--------------------------------
            $Destination = "$FileDir\dipatch_req.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_1
                    }
            #--------------------------------
            $Destination = "$FileDir\dispatch_up_req.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_2
                    }
            #--------------------------------
            $Destination = "$FileDir\nl2_utt_ucr_upd.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_3
                    }
            #--------------------------------
            $Destination = "$FileDir\type_II_out_adv.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_4
                    }
            #--------------------------------
            $Destination = "$FileDir\type_II_upd_req.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_5
                    }
            #--------------------------------
            $Destination = "$FileDir\tick_inv_num.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_6
                    }
            #--------------------------------
            $Destination = "$FileDir\site_access_req.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_7
                    }
            #--------------------------------
            $Destination = "$FileDir\major_out_adv.docx"
            if (!(Test-Path -Path $Destination)) {
                    payload_deploy_8
                    }
            #--------------------------------
}
