#...........................rtts app uninstaller START
function uninstall_rtts {
        # If the current directory is within the folder to delete, switch to a different directory first
        if ("$($PWD.Path)\\" -like "$PSScriptRoot\\*") {
            Push-Location C:\ 
        }
        # Remove the script's parent folder as a whole
        Remove-Item -LiteralPath $PSScriptRoot -Recurse -Force
    }
#------------------------------------------# Create the uninstaller form
function uninstall_rtts_formUNI {
    $formUNI = New-Object system.Windows.Forms.Form -Property @{
        ClientSize = New-Object System.Drawing.Point 490,100
        Text       = "uninstaller"
    }
     $groupBoxUNI = New-Object System.Windows.Forms.GroupBox
     $groupBoxUNI.Text = "Attention"
     $groupBoxUNI.ForeColor = [System.Drawing.Color]::Red
     $groupBoxUNI.Size = New-Object System.Drawing.Size(440, 65)
     $groupBoxUNI.Location = New-Object System.Drawing.Point(20,15)
     $groupBoxUNI.Font = New-Object System.Drawing.Font("Arial",11,[System.Drawing.FontStyle]::Bold)
     $groupBoxUNI.Visible = $true
     #--------------------------------
     $textBoxUNI = New-Object System.Windows.Forms.TextBox
     $textBoxUNI.Location = New-Object System.Drawing.Size(15,20)
     $textBoxUNI.Size = New-Object System.Drawing.Size(410,50)
     $textBoxUNI.Visible = $true
     $textBoxUNI.Text = "Uninstalling in backgroud....Thank you for using our app!"
     $textBoxUNI.ForeColor = [System.Drawing.Color]::GreenYellow
     $textBoxUNI.BackColor = [System.Drawing.Color]::Black
     $groupBoxUNI.Controls.Add($textBoxUNI)

    # Add a button to trigger self-deletion
    $btnSelfDestruct = New-Object system.Windows.Forms.Button -Property @{
        Text     = "confirm"
        Location = New-Object System.Drawing.Point 200, 70
    }
    $formUNI.Controls.Add($btnSelfDestruct)
    $formUNI.Controls.Add($groupBoxUNI)

    # Event handler for button click
    $btnSelfDestruct.Add_Click({
            $form.Close()
            $from.Dispose()
            $formUNI.Close()
            $formUNI.Dispose()
            uninstall_rtts
            })
            $formUNI.Add_Shown({ $form.Activate() })
            [void]$formUNI.ShowDialog()
}
